import {useState} from 'react';
import swal from 'sweetalert';

const Adduser = () =>{
let [username, pickname] = useState("");
let [useremail, pickemail] = useState("");
let [usermobile, pickmobile] = useState("");

const validate = () => {
    let status = true;

   //name check
    if(name == "") {
    status = false;
      document.getElementById("nameerror").innerText =
        "Please fill name field ! ";
    } else {
      document.getElementById("nameerror").innerText = "";
    }

    // emailcheck
    if(email == "") {
    status = false;
      document.getElementById("emailerror").innerText =
        "Please fill email field ! ";
    } else {
      document.getElementById("emailerror").innerText = "";
    }


    // passwordcheck
    if(password == "") {
       status = false;
         document.getElementById("passworderror").innerText =
           "Please fill password field ! ";
       } else {
         document.getElementById("passworderror").innerText = "";
       }

       //mobilecheck
       if(mobile == "") {
          status = false;
            document.getElementById("mobileerror").innerText =
              "Please fill mobile field ! ";
          } else {
            document.getElementById("mobileerror").innerText = "";
          }
       
       //sourcecheck
    if(source == "") {
       status = false;
         document.getElementById("sourceerror").innerText =
           "Please fill source field ! ";
       } else {
         document.getElementById("sourceerror").innerText = "";
       }
   

        //gendercheck
    if(gender == "") {
       status = false;
         document.getElementById("gendererror").innerText =
           "Please fill gender field ! ";
       } else {
         document.getElementById("gendererror").innerText = "";
       }
   

       // citycheck
    if(city == "") {
       status = false;
         document.getElementById("cityerror").innerText =
           "Please fill city field ! ";
       } else {
         document.getElementById("cityerror").innerText = "";
       }

       
     // statecheck
    if(keyword == "") {
       status = false;
         document.getElementById("stateerror").innerText =
           "Please fill state field ! ";
       } else {
         document.getElementById("stateerror").innerText = "";
       }

    
    if(status) {save();}
   

  };

   const Add = () => {
    let url = "http://localhost:3333/user";
    let finaldata =  new Date().toLocaleString() ;
    let userdata = 
    {
       name: username,
       email : useremail,
       mobile : usermobile,
       date: finaldata
    } 

    let postdata = 
    {
     headers : {'Content-type' : 'application/json'},
     method: "POST",
     body : JSON.stringify(userdata)
    }

    fetch(url, postdata)
    .then(responsedata => responsedata.json())
    .then(data => {
     swal("User Added Successfully !!", "", "success");
     window.location.href = "http://localhost:3000/#/";
   })
}

    return (
    // <div className="container mt-5">
    //     <div className="row">
    //         <div className="col-lg-3"></div>
    //         <div className="col-lg-6">
    //             <div className="border p-4 rounded shadow">
    //                 <h3 className="text-center"> User details </h3>

    //                 <div className="mb-4">
    //                     <label>Name</label>
    //                     <input type="text"  className="form-control" value={username} onChange={obj=> pickname(obj.target.value)}/> 
    //                 </div>

    //                 <div className="mb-4">
    //                     <label>Email </label>
    //                     <input type="email"  className="form-control" value={useremail} onChange={obj=> pickemail(obj.target.value)}/> 
    //                 </div>

    //                 <div className="mb-3">
    //                     <label>Mobile</label>
    //                     <input type="number" className="form-control" value={usermobile} onChange={obj=> pickmobile(obj.target.value)}/>
    //                 </div>

    //                 <div className="text-center">
    //                     <button className="btn btn-danger" onClick={Add}>Add user</button>
    //                 </div>
    //             </div>
    //         </div>
    //     </div>
    //  </div>

    <div className="container mt-4">
    <div className="row">
        <div className="col-lg-3"> </div>
        <div className="col-lg-6 text-center border bg-light text-dark p-5 rounded mt-5"> 
          <h1 className=" text-primary mb-3"> Add User </h1>

           <table className=' table '>
               <thead>
                <tr>
                <th>User's Name :</th>
                <td colSpan={2}> <input type="text" placeholder="Enter User Name" className="form-control" value={username} onChange={obj=> pickname(obj.target.value)}/>  </td>
                </tr>

                <tr>
                <th>User's Email :</th>
                <td colSpan={2}><input type="email" placeholder="Enter User Email" className="form-control" value={useremail} onChange={obj=> pickemail(obj.target.value)}/>  </td>
                </tr>

                <tr>
                <th>User's mobile :</th>
                <td colSpan={2}> <input type="number" className="form-control" placeholder="Enter User Mobile" value={usermobile} onChange={obj=> pickmobile(obj.target.value)}/></td>
                </tr>

                <tr>
                <td colSpan={3}> <button className="btn btn-danger" onClick={Add}>Add user</button></td>
                </tr>
               </thead>
           </table>
         </div> 

         <div className="col-lg-3"> </div>
         </div> 
    </div>  
    )
}

export default Adduser;
